function pick(obj, paths) {
  for (const p of paths) {
    const parts = p.split('.');
    let cur = obj;
    let ok = true;
    for (const part of parts) {
      if (!cur || typeof cur !== 'object' || !(part in cur)) {
        ok = false;
        break;
      }
      cur = cur[part];
    }
    if (ok && cur !== undefined && cur !== null && String(cur).trim() !== '') return cur;
  }
  return '';
}

function toDigits(v) {
  return String(v || '').replace(/\D+/g, '');
}

function detectText(obj) {
  const text = pick(obj, [
    'text', 'body', 'message', 'caption', 'data.text', 'data.body', 'data.message', 'data.caption', 'content.text', 'content.body', 'msg'
  ]);
  return String(text || '').trim();
}

const input = $input.first()?.json || {};
const query = (input.query && typeof input.query === 'object') ? input.query : {};
const eventHint = String(query.event || query.type || input.event || input.type || input.topic || input?.data?.event || input?.data?.type || '').toLowerCase();
const tenantId = String(input.tenant_id || $env.LARA_TENANT_ID || 'default').trim() || 'default';
const out = [];

const messageCandidates = [];
if (Array.isArray(input.messages)) messageCandidates.push(...input.messages);
if (Array.isArray(input.data?.messages)) messageCandidates.push(...input.data.messages);
if (Array.isArray(input.data?.data?.messages)) messageCandidates.push(...input.data.data.messages);
if (Array.isArray(input.payload?.messages)) messageCandidates.push(...input.payload.messages);
if (input.message && typeof input.message === 'object') messageCandidates.push(input.message);
if (input.data && typeof input.data === 'object' && !Array.isArray(input.data) && detectText(input.data)) messageCandidates.push(input.data);
if (detectText(input) && messageCandidates.length === 0) messageCandidates.push(input);

const statusCandidates = [];
if (Array.isArray(input.messages_update)) statusCandidates.push(...input.messages_update);
if (Array.isArray(input.statuses)) statusCandidates.push(...input.statuses);
if (Array.isArray(input.data?.messages_update)) statusCandidates.push(...input.data.messages_update);
if (Array.isArray(input.data?.statuses)) statusCandidates.push(...input.data.statuses);
if (Array.isArray(input.data?.updates)) statusCandidates.push(...input.data.updates);
if (Array.isArray(input.payload?.messages_update)) statusCandidates.push(...input.payload.messages_update);
if (Array.isArray(input.payload?.statuses)) statusCandidates.push(...input.payload.statuses);
if (input.update && typeof input.update === 'object') statusCandidates.push(input.update);

const looksLikeStatus = eventHint.includes('update') || eventHint.includes('status');
const looksLikeMessage = eventHint.includes('message') || eventHint.includes('msg');

for (const msg of messageCandidates) {
  const waDigits = toDigits(pick(msg, ['from','number','phone','sender','author','chatId','remoteJid','data.from','data.number','data.phone']));
  const text = detectText(msg);
  if (!waDigits || !text) continue;

  const id = String(pick(msg, ['id','messageId','key.id']) || (waDigits + '-' + Date.now())).trim();
  const tsRaw = pick(msg, ['timestamp','ts','time','data.timestamp']);
  const tsNumber = Number(tsRaw);
  const receivedAt = Number.isFinite(tsNumber) && tsNumber > 0 ? new Date(tsNumber * 1000).toISOString() : new Date().toISOString();

  out.push({
    json: {
      event_type: 'inbound',
      event_id: id,
      wa_id: waDigits,
      telefone: waDigits,
      message_text: text,
      tenant_id: tenantId,
      jurisdicao: 'BR',
      canal: 'WHATSAPP',
      received_at: receivedAt,
      payload: { provider: 'uazapi', event_hint: eventHint, raw_message: msg, raw_payload: input },
    },
  });
}

for (const st of statusCandidates) {
  const messageId = String(pick(st, ['id','messageId','key.id']) || '').trim();
  const waDigits = toDigits(pick(st, ['to','to_number','recipient','from','number','phone','remoteJid']));
  const status = String(pick(st, ['status','state','event']) || '').trim();
  if (!messageId || !status) continue;

  const tsRaw = pick(st, ['timestamp','ts','time']);
  const tsNumber = Number(tsRaw);
  const timestamp = Number.isFinite(tsNumber) && tsNumber > 0 ? new Date(tsNumber * 1000).toISOString() : new Date().toISOString();

  out.push({
    json: {
      event_type: 'status',
      event_id: messageId + ':' + status + ':' + timestamp,
      message_id: messageId,
      wa_id: waDigits,
      status,
      timestamp,
      tenant_id: tenantId,
      payload: { provider: 'uazapi', event_hint: eventHint, raw_status: st, raw_payload: input },
    },
  });
}

if (out.length === 0 && looksLikeMessage && detectText(input)) {
  const waDigits = toDigits(pick(input, ['from','number','phone','sender','author','chatId','remoteJid']));
  const text = detectText(input);
  if (waDigits && text) {
    out.push({
      json: {
        event_type: 'inbound',
        event_id: String(pick(input, ['id','messageId']) || (waDigits + '-' + Date.now())),
        wa_id: waDigits,
        telefone: waDigits,
        message_text: text,
        tenant_id: tenantId,
        jurisdicao: 'BR',
        canal: 'WHATSAPP',
        received_at: new Date().toISOString(),
        payload: { provider: 'uazapi', event_hint: eventHint, raw_payload: input },
      },
    });
  }
}

if (out.length === 0 && looksLikeStatus) {
  const messageId = String(pick(input, ['id','messageId']) || '').trim();
  const status = String(pick(input, ['status','state','event']) || '').trim();
  if (messageId && status) {
    out.push({
      json: {
        event_type: 'status',
        event_id: messageId + ':' + status + ':' + new Date().toISOString(),
        message_id: messageId,
        wa_id: toDigits(pick(input, ['to','to_number','recipient','from','number','phone'])),
        status,
        timestamp: new Date().toISOString(),
        tenant_id: tenantId,
        payload: { provider: 'uazapi', event_hint: eventHint, raw_payload: input },
      },
    });
  }
}

return out;

const output = [];
for (const item of $input.all()) {
  const d = item.json || {};
  if (String(d.status || '').toLowerCase() !== 'ok') continue;

  const number = String(d.wa_id || '').replace(/\D+/g, '').trim();
  const text = String(d.mensagem || '').trim();
  if (!number || !text) continue;

  output.push({
    json: {
      number,
      text,
      linkPreview: false,
      replyid: '',
      mentions: '',
      readchat: true,
      delay: 0,
      lara_acao: String(d.acao || ''),
      lara_status: String(d.status || ''),
      codcli: d.codcli || '',
      cliente: d.cliente || '',
    },
  });
}
return output;
